import React from 'react'
import { render, cleanup } from '@testing-library/react'
import I18nProvider from '../src/I18nProvider'
import useTranslation from '../src/useTranslation'

// Make sure globalThis.__NEXT_TRANSLATE__ is NOT set (simulating pages router without appWithI18n)
delete globalThis.__NEXT_TRANSLATE__

describe('I18nProvider lang prop reproduction', () => {
  afterEach(() => {
    cleanup()
    delete globalThis.__NEXT_TRANSLATE__
  })

  test('should use the lang prop passed to I18nProvider', () => {
    const Inner = () => {
      const { t, lang } = useTranslation()
      return <>{lang}:{t('common:title')}</>
    }

    const namespaces = {
      common: {
        title: 'Hello',
      },
    }

    const { container } = render(
      <I18nProvider lang="es" namespaces={namespaces}>
        <Inner />
      </I18nProvider>
    )
    expect(container.textContent).toBe('es:Hello')
  })

  test('should update lang when I18nProvider lang prop changes', () => {
    const Inner = () => {
      const { t, lang } = useTranslation()
      return <>{lang}:{t('common:title')}</>
    }

    const namespaces = {
      common: {
        title: 'Hello',
      },
    }

    // Render with "en"
    const { container, rerender } = render(
      <I18nProvider lang="en" namespaces={namespaces}>
        <Inner />
